import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Apple Ads & iOS 14 FAQ","description":"","frontmatter":{"title":"Apple Ads & iOS 14 FAQ","slug":"apple-ads-ios-14-faq"},"headers":[],"relativePath":"marketer-hub/apple-ads-ios-14-faq.md","filePath":"marketer-hub/apple-ads-ios-14-faq.md"}'),o={name:"marketer-hub/apple-ads-ios-14-faq.md"};function s(d,e,l,n,p,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<details><summary>When will the Branch SDK be updated to use the new AdServices API for Apple Ads?</summary><p>Branch has updated to the new AdServices API. The new Apple Ads framework requires Branch iOS SDK <a href="./ios-version-history.html">v1.39.0</a>.</p><p>As of February 1st, 2022 the Campaign Management API is deprecated which is used to pull cost, click, and impression data, and not the iAD framework used for attribution. If you are on this legacy iAd framework, you just need to authenticate your Apple Ads account in the Branch Dashboard to get clicks, cost and impression data reporting.</p></details><details><summary>How will Apple Ads work on iOS 14? Will they use SKAdNetwork?</summary><p>Unlike all other ad networks, Apple is not requiring Apple Ads to use the SKAdNetwork framework. However, they are moving to a new API called <a href="https://developer.apple.com/documentation/adservices" target="_blank" rel="noreferrer">AdServices</a>, which will provide attribution with a similar degree of user privacy but slightly better data granularity.</p><p>Compared to the legacy iAd framework used by Apple Ads prior to iOS 14, the new AdServices API has the benefit of working for <em>all</em> users (previously, iAd would not return a result if the user had Limit Ad Tracking enabled), but offers less data granularity.</p><p>We are adjusting our integration to implement these changes, and we will share additional details as we learn more.</p></details><details><summary>Will Branch still show keyword-level breakdowns of Apple Ads data?</summary><p>The new <a href="https://developer.apple.com/documentation/adservices/aaattribution/3697093-attributiontoken#3697463" target="_blank" rel="noreferrer">AdServices API</a> returns a <code>keywordId</code> parameter, but does not return the exact keyword text like the old iAd API did.</p><p>Initially, <code>keywordId</code> data will be available via data exports. We hope to make additional Apple Ads keyword insights available again in future.</p></details>',3)])])}const m=a(o,[["render",s]]);export{c as __pageData,m as default};
